"use client";

import { useEffect, useState, useCallback } from "react";
import { useParams } from "next/navigation";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { CodeEditor } from "@/components/editor/CodeEditor";
import { LanguageSelector } from "@/components/editor/LanguageSelector";
import { getGenericTemplate } from "@/lib/code-templates";
import { Textarea } from "@/components/ui/textarea";
import { CheckCircle2, XCircle, Clock, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";

type Problem = {
  id: string;
  title: string;
  statement: string;
  constraints: string | null;
  inputFormat: string | null;
  outputFormat: string | null;
  difficulty: number;
  topic: string | null;
  testCases?: { id: string; input: string; expectedOutput: string; isSample: boolean }[];
  sampleTestCases?: { id: string; input: string; expectedOutput: string; isSample: boolean }[];
};

type TestResult = {
  passed: number;
  total: number;
  results?: Array<{
    input: string;
    expected: string;
    output: string;
    passed: boolean;
  }>;
};

type Submission = {
  id: string;
  status: string;
  language: string;
  createdAt: string;
};

export default function QuestionDetailPage() {
  const params = useParams();
  const id = params.id as string;

  const [problem, setProblem] = useState<Problem | null>(null);
  const [loading, setLoading] = useState(true);
  const [language, setLanguage] = useState("python");
  const [code, setCode] = useState(DEFAULT_CODE["python"]);
  const [running, setRunning] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  const fetchProblem = useCallback(async () => {
    try {
      const res = await fetch(`/api/problems/${id}`);
      if (!res.ok) throw new Error("Failed to load problem");
      const data = await res.json();
      setProblem(data);
    } catch {
      toast.error("Failed to load problem");
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    fetchProblem();
  }, [fetchProblem]);

  const handleRun = async () => {
    if (!problem) return;
    setRunning(true);
    setResult(null);
    try {
      const res = await fetch("/api/run", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ problemId: problem.id, code, language }),
      });
      const data = await res.json();
      setResult(data.message ?? "Run completed");
      toast(data.message ?? "Run completed");
    } catch {
      toast.error("Run failed");
    } finally {
      setRunning(false);
    }
  };

  const handleSubmit = async () => {
    if (!problem) return;
    setRunning(true);
    setResult(null);
    try {
      const res = await fetch("/api/submit", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ problemId: problem.id, code, language }),
      });
      const data = await res.json();
      setResult(data.status === "accepted" ? "Accepted!" : "Submission received");
      toast(data.status === "accepted" ? "Accepted!" : "Submission received");
    } catch {
      toast.error("Submit failed");
    } finally {
      setRunning(false);
    }
  };

  if (loading) return <div className="p-8">Loading problem…</div>;
  if (!problem) return <div className="p-8 text-destructive">Problem not found.</div>;

  const sampleCases = problem.testCases?.filter((tc) => tc.isSample) ?? problem.sampleTestCases ?? [];

  return (
    <div className="flex flex-col lg:flex-row gap-4 h-[calc(100vh-8rem)]">
      {/* Left: Problem Statement */}
      <div className="lg:w-1/2 overflow-auto border rounded-lg bg-card p-4">
        <h1 className="text-xl font-bold mb-1">{problem.title}</h1>
        <div className="flex gap-2 text-xs text-muted-foreground mb-4">
          <span>Level {problem.difficulty}</span>
          {problem.topic && <span>· {problem.topic}</span>}
        </div>
        <div className="prose prose-sm dark:prose-invert max-w-none">
          <div dangerouslySetInnerHTML={{ __html: problem.statement }} />
        </div>
        {problem.constraints && (
          <div className="mt-4">
            <h3 className="font-medium text-sm">Constraints</h3>
            <pre className="text-xs whitespace-pre-wrap mt-1">{problem.constraints}</pre>
          </div>
        )}
        {problem.inputFormat && (
          <div className="mt-4">
            <h3 className="font-medium text-sm">Input Format</h3>
            <pre className="text-xs whitespace-pre-wrap mt-1">{problem.inputFormat}</pre>
          </div>
        )}
        {problem.outputFormat && (
          <div className="mt-4">
            <h3 className="font-medium text-sm">Output Format</h3>
            <pre className="text-xs whitespace-pre-wrap mt-1">{problem.outputFormat}</pre>
          </div>
        )}
        {sampleCases.length > 0 && (
          <div className="mt-4">
            <h3 className="font-medium text-sm mb-2">Sample Test Cases</h3>
            {sampleCases.map((tc, i) => (
              <div key={tc.id} className="mb-3 border rounded p-2 bg-muted/30 text-xs">
                <p className="font-medium">Example {i + 1}</p>
                <p className="mt-1"><span className="font-medium">Input:</span></p>
                <pre className="whitespace-pre-wrap">{tc.input}</pre>
                <p className="mt-1"><span className="font-medium">Output:</span></p>
                <pre className="whitespace-pre-wrap">{tc.expectedOutput}</pre>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Right: Editor + Actions */}
      <div className="lg:w-1/2 flex flex-col min-h-0">
        <div className="flex items-center gap-2 mb-2">
          <LanguageSelector
            value={language}
            onChange={(lang) => {
              setLanguage(lang);
              if (!code.trim() || code === DEFAULT_CODE[language]) {
                setCode(DEFAULT_CODE[lang] ?? "// Write your code here\n");
              }
            }}
          />
          <Button size="sm" onClick={handleRun} disabled={running}>
            {running ? "Running…" : "Run"}
          </Button>
          <Button size="sm" variant="secondary" onClick={handleSubmit} disabled={running}>
            Submit
          </Button>
        </div>
        <div className="flex-1 min-h-[350px] border rounded-lg overflow-hidden">
          <CodeEditor
            value={code}
            onChange={setCode}
            language={language}
            height="100%"
          />
        </div>
        {result && (
          <Card className="mt-2">
            <CardContent className="p-3">
              <p className="text-sm font-medium">{result}</p>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  );
}
